CREATE TABLE IF NOT EXISTS b2b_marketplace_suppliers (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NULL, legal_name VARCHAR(160) NOT NULL, city VARCHAR(80), state_code CHAR(2), rating NUMERIC(3,2) NOT NULL DEFAULT 0, is_featured BOOLEAN NOT NULL DEFAULT FALSE);
CREATE TABLE IF NOT EXISTS b2b_marketplace_categories (id BIGSERIAL PRIMARY KEY, category_name VARCHAR(120) NOT NULL UNIQUE);
CREATE TABLE IF NOT EXISTS b2b_marketplace_products (id BIGSERIAL PRIMARY KEY, supplier_id BIGINT NOT NULL REFERENCES b2b_marketplace_suppliers(id), category_id BIGINT NOT NULL REFERENCES b2b_marketplace_categories(id), product_name VARCHAR(160) NOT NULL, sku VARCHAR(60), min_order_qty INT NOT NULL DEFAULT 1, is_active BOOLEAN NOT NULL DEFAULT TRUE);
CREATE TABLE IF NOT EXISTS b2b_product_prices (id BIGSERIAL PRIMARY KEY, product_id BIGINT NOT NULL REFERENCES b2b_marketplace_products(id), price NUMERIC(14,2) NOT NULL, valid_from DATE NOT NULL DEFAULT CURRENT_DATE);
CREATE TABLE IF NOT EXISTS b2b_bulk_price_rules (id BIGSERIAL PRIMARY KEY, product_id BIGINT NOT NULL REFERENCES b2b_marketplace_products(id), min_qty INT NOT NULL, discount_percentage NUMERIC(7,4) NOT NULL);
CREATE TABLE IF NOT EXISTS b2b_marketplace_orders (id BIGSERIAL PRIMARY KEY, buyer_tenant_id BIGINT NOT NULL, supplier_id BIGINT NOT NULL REFERENCES b2b_marketplace_suppliers(id), status VARCHAR(20) NOT NULL DEFAULT 'OPEN', total_amount NUMERIC(14,2) NOT NULL DEFAULT 0, created_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS b2b_marketplace_order_items (id BIGSERIAL PRIMARY KEY, order_id BIGINT NOT NULL REFERENCES b2b_marketplace_orders(id), product_id BIGINT NOT NULL REFERENCES b2b_marketplace_products(id), quantity INT NOT NULL, unit_price NUMERIC(14,2) NOT NULL);
CREATE TABLE IF NOT EXISTS b2b_supplier_reviews (id BIGSERIAL PRIMARY KEY, supplier_id BIGINT NOT NULL REFERENCES b2b_marketplace_suppliers(id), reviewer_tenant_id BIGINT NOT NULL, score INT NOT NULL, comment TEXT);
CREATE TABLE IF NOT EXISTS b2b_supplier_promotions (id BIGSERIAL PRIMARY KEY, supplier_id BIGINT NOT NULL REFERENCES b2b_marketplace_suppliers(id), title VARCHAR(140) NOT NULL, discount_percentage NUMERIC(7,4) NOT NULL, starts_at DATE NOT NULL, ends_at DATE NOT NULL);
CREATE TABLE IF NOT EXISTS b2b_marketplace_commissions (id BIGSERIAL PRIMARY KEY, order_id BIGINT NOT NULL REFERENCES b2b_marketplace_orders(id), commission_percentage NUMERIC(7,4) NOT NULL, commission_amount NUMERIC(14,2) NOT NULL);
CREATE OR REPLACE VIEW vw_b2b_marketplace_sales AS SELECT o.id,o.buyer_tenant_id,o.total_amount,o.status,o.created_at FROM b2b_marketplace_orders o;
